import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"31A. Doctor Records","description":"","frontmatter":{"title":"31A. Doctor Records","eba":"Medical Specialists 2022-2026","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/wages/31A-doctor-records.md","filePath":"ebas/medical-specialists/wages/31A-doctor-records.md"}'),n={name:"ebas/medical-specialists/wages/31A-doctor-records.md"};function s(i,e,c,p,d,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_31a-doctor-records" tabindex="-1">31A. Doctor Records <a class="header-anchor" href="#_31a-doctor-records" aria-label="Permalink to &quot;31A. Doctor Records&quot;">​</a></h1><p><strong>31A.1</strong> Doctor Records</p><p><strong>(a)</strong> The Act and Regulations set out an Employer&#39;s obligations with respect to record keeping including but not limited to:</p><p><strong>(i)</strong> a requirement to keep a record that sets out any leave the Doctor takes and the balance (if any) of the Doctor&#39;s entitlement to that leave from time to time;</p><p><strong>(ii)</strong> the inspection and copying of a Doctor record by the Doctor or former Doctor to whom the record relates; and</p><p><strong>(iii)</strong> the requirement to keep accurate Doctor records.</p><p><strong>(b)</strong> Where an Employer records time and attendance on a Doctor’s electronic timecard in excess of the record keeping requirements of the Act and</p><p>Regulations, a Doctor (or their representative) may request in writing that the Employer make copies of the electronic timecards available within 14 days.</p><p><strong>(c)</strong> An Employer is not in breach of this clause, the Act or the Regulations if records prescribed at (a) have not been retained and are unable to be produced.</p><p><strong>31A.2</strong> Payslips</p><p><strong>(a)</strong> The Act and Regulations set out an Employer&#39;s obligations with respect to pay slips, including but not limited to a requirement to specify:</p><p><strong>(i)</strong> the period to which the pay slip relates;</p><p><strong>(ii)</strong> the amount of wages to which the Doctor is entitled;</p><p><strong>(iii)</strong> if an amount was deducted from the gross amount of the payment, the name or the name and number of the fund or account into which the deduction was paid; and</p><p><strong>(iv)</strong> the net amount for each payment.</p><p><strong>(b)</strong> To the extent reasonably practicable, payslips will record a Doctor&#39;s accrued annual leave and personal leave.</p><p><strong>(c)</strong> Where an adjustment is made to the Doctor’s pay to reflect an error arising from another pay period (such as overpayment or an entitlement to an additional payment) the Doctor will be advised in writing.</p><p>Note: in the event of a proposed deduction for an overpayment, please see <a href="/eba/ebas/medical-specialists/wages/35-recovery-of-overpayments.html">clause 35</a> Recovery of Overpayments.</p><p><strong>(d)</strong> Payslips are important to ensuring that Doctors can be satisfied they are being paid correctly. Where a Doctor has a query about the content of their payslip, the Doctor may:</p><p><strong>(i)</strong> raise that query with the Medical Workforce Unit or Payroll Department (where applicable); and</p><p><strong>(ii)</strong> request that the Association, including the Ambassador, raise any query with the Medical Workforce Unit or Payroll Department (where applicable) on their behalf.</p>',21)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
